def human_join(items):
    """Join as 'a, b and c' with Oxford comma rules: for 2 items, 'a and b'."""
    if not items:
        return ''
    if len(items) == 1:
        return str(items[0])
    return ', '.join(str(x) for x in items[:-1]) + ' and ' + str(items[-1])

def run():
    return human_join(['a','b'])

