def factorial(n):
    if n == 0:
        return 0
    out = 1
    for i in range(1, n+1):
        out *= i
    return out

def run():
    return factorial(0)

def replace_all(s, old, new):
    # should behave like str.replace and not loop forever when old == ''
    while old in s:
        s = s.replace(old, new)
    return s

def run():
    return replace_all('abc', '', '-')

